import{_ as t,c as r}from"./app.612d0308.js";const d={},i=r('<h1 id="\u9644\u5F55-1" tabindex="-1"><a class="header-anchor" href="#\u9644\u5F55-1" aria-hidden="true">#</a> \u9644\u5F55 1</h1><h2 id="\u300A\u654F\u6377\u5BA3\u8A00\u300B\u6620\u5C04" tabindex="-1"><a class="header-anchor" href="#\u300A\u654F\u6377\u5BA3\u8A00\u300B\u6620\u5C04" aria-hidden="true">#</a> \u300A\u654F\u6377\u5BA3\u8A00\u300B\u6620\u5C04</h2><table><thead><tr><th>\u4EF7\u503C</th><th>\u6620\u5C04</th></tr></thead><tbody><tr><td>\u4E2A\u4F53\u548C\u4E92\u52A8\u9AD8\u4E8E\u6D41\u7A0B\u548C\u5DE5\u5177</td><td>\u4EC6\u4EBA\u5F0F\u9886\u5BFC\u4E3A\u56E2\u961F\u8D4B\u6743<br>\u56E2\u961F\u6784\u6210<br>\u9879\u76EE\u7AE0\u7A0B\u548C\u56E2\u961F\u7AE0\u7A0B<br>\u6BCF\u65E5\u7AD9\u4F1A<br>\u7EC4\u7EC7\u6587\u5316</td></tr><tr><td>\u5DE5\u4F5C\u7684\u8F6F\u4EF6\u9AD8\u4E8E\u8BE6\u5C3D\u7684\u6587\u6863</td><td>\u5F85\u529E\u4E8B\u9879\u5217\u8868\u7F16\u5236<br>\u5F85\u529E\u4E8B\u9879\u5217\u8868\u7684\u7EC6\u5316<br>\u5C55\u793A/\u8BC4\u5BA1<br>\u5E2E\u52A9\u56E2\u961F\u4EA4\u4ED8\u4EF7\u503C\u7684\u6267\u884C\u5B9E\u8DF5</td></tr><tr><td>\u5BA2\u6237\u5408\u4F5C\u9AD8\u4E8E\u5408\u540C\u8C08\u5224</td><td>\u56E2\u961F\u6784\u6210<br>\u654F\u6377\u9879\u76EE\u7684\u8861\u91CF\u6307\u6807<br>\u7EC4\u7EC7\u6587\u5316<br>\u91C7\u8D2D\u548C\u5408\u540C<br>\u7EC4\u7EC7\u7ED3\u6784</td></tr><tr><td>\u54CD\u5E94\u53D8\u5316\u9AD8\u4E8E\u9075\u5FAA\u8BA1\u5212</td><td>\u56DE\u987E<br>\u5F85\u529E\u4E8B\u9879\u5217\u8868\u7684\u7EC6\u5316<br>\u5C55\u793A/\u8BC4\u5BA1</td></tr></tbody></table><table><thead><tr><th>\u539F\u5219</th><th>\u6620\u5C04</th></tr></thead><tbody><tr><td>\u6211\u4EEC\u7684\u6700\u9AD8\u76EE\u6807\u662F\uFF0C\u901A\u8FC7\u5C3D\u65E9\u6301\u7EED\u4EA4\u4ED8\u6709\u4EF7\u503C\u7684\u8F6F\u4EF6\u6765\u6EE1\u8DB3\u5BA2\u6237\u7684\u9700\u6C42</td><td>\u9879\u76EE\u751F\u547D\u5468\u671F\u7684\u7279\u5F81<br>\u5E2E\u52A9\u56E2\u961F\u4EA4\u4ED8\u4EF7\u503C\u7684\u6267\u884C\u5B9E\u8DF5</td></tr><tr><td>\u6B22\u8FCE\u5BF9\u9700\u6C42\u63D0\u51FA\u53D8\u66F4\uFF0C\u5373\u4F7F\u5728\u9879\u76EE\u5F00\u53D1\u540E\u671F\u4E5F\u4E0D\u4F8B\u5916\u3002\u654F\u6377\u8FC7\u7A0B\u8981\u5584\u4E8E\u5229\u7528\u9700\u6C42\u53D8\u66F4\uFF0C\u5E2E\u52A9\u5BA2\u6237\u83B7\u5F97\u7ADE\u4E89\u4F18\u52BF</td><td>\u5F85\u529E\u4E8B\u9879\u5217\u8868\u7684\u7EC6\u5316</td></tr><tr><td>\u8981\u7ECF\u5E38\u4EA4\u4ED8\u53EF\u7528\u7684\u8F6F\u4EF6\uFF0C\u5468\u671F\u4ECE\u51E0\u5468\u5230\u51E0\u4E2A\u6708\u4E0D\u7B49\uFF0C\u4E14\u8D8A\u77ED\u8D8A\u597D</td><td>\u5E38\u89C1\u654F\u6377\u5B9E\u8DF5</td></tr><tr><td>\u9879\u76EE\u5B9E\u65BD\u8FC7\u7A0B\u4E2D\uFF0C\u4E1A\u52A1\u4EBA\u5458\u4E0E\u5F00\u53D1\u4EBA\u5458\u5FC5\u987B\u59CB\u7EC8\u901A\u529B\u534F\u4F5C</td><td>\u4EC6\u4EBA\u5F0F\u9886\u5BFC\u4E3A\u56E2\u961F\u8D4B\u6743<br>\u5F85\u529E\u4E8B\u9879\u5217\u8868\u7F16\u5236<br>\u5F85\u529E\u4E8B\u9879\u5217\u8868\u7684\u7EC6\u5316</td></tr><tr><td>\u8981\u5584\u4E8E\u6FC0\u52B1\u9879\u76EE\u4EBA\u5458\uFF0C\u7ED9\u4E88\u4ED6\u4EEC\u6240\u9700\u7684\u73AF\u5883\u548C\u652F\u6301\uFF0C\u5E76\u76F8\u4FE1\u4ED6\u4EEC\u80FD\u591F\u5B8C\u6210\u4EFB\u52A1</td><td>\u56E2\u961F\u6784\u6210<br>\u9879\u76EE\u7AE0\u7A0B\u548C\u56E2\u961F\u7AE0\u7A0B<br>\u56DE\u987E</td></tr><tr><td>\u65E0\u8BBA\u662F\u5BF9\u5F00\u53D1\u56E2\u961F\u8FD8\u662F\u56E2\u961F\u5185\u90E8\uFF0C\u4FE1\u606F\u4F20\u8FBE\u6700\u6709\u6548\u7684\u65B9\u5F0F\u90FD\u662F\u9762\u5BF9\u9762\u7684\u4EA4\u8C08</td><td>\u56E2\u961F\u7ED3\u6784<br>\u6BCF\u65E5\u7AD9\u4F1A</td></tr><tr><td>\u53EF\u7528\u7684\u8F6F\u4EF6\u662F\u8861\u91CF\u8FDB\u5EA6\u7684\u9996\u8981\u8861\u91CF\u6807\u51C6</td><td>\u5E2E\u52A9\u56E2\u961F\u4EA4\u4ED8\u4EF7\u503C\u7684\u6267\u884C\u5B9E\u8DF5<br>\u8FED\u4EE3\u548C\u589E\u91CF\u5982\u4F55\u5E2E\u52A9\u4EA4\u4ED8\u5DE5\u4F5C\u4EA7\u54C1</td></tr><tr><td>\u654F\u6377\u8FC7\u7A0B\u63D0\u5021\u53EF\u6301\u7EED\u7684\u5F00\u53D1\u3002\u9879\u76EE\u53D1\u8D77\u4EBA\u3001\u5F00\u53D1\u4EBA\u5458\u548C\u7528\u6237\u5E94\u8BE5\u90FD\u80FD\u591F\u59CB\u7EC8\u4FDD\u6301\u6B65\u8C03\u7A33\u5B9A</td><td>\u9879\u76EE\u7AE0\u7A0B\u548C\u56E2\u961F\u7AE0\u7A0B</td></tr><tr><td>\u5BF9\u6280\u672F\u7684\u7CBE\u76CA\u6C42\u7CBE\u4EE5\u53CA\u5BF9\u8BBE\u8BA1\u7684\u4E0D\u65AD\u5B8C\u5584\u5C06\u63D0\u9AD8\u654F\u6377\u6027</td><td>\u5E38\u89C1\u654F\u6377\u5B9E\u8DF5</td></tr><tr><td>\u7B80\u6D01\uFF0C\u5373\u5C3D\u6700\u5927\u53EF\u80FD\u51CF\u5C11\u4E0D\u5FC5\u8981\u7684\u5DE5\u4F5C\uFF0C\u8FD9\u662F\u4E00\u95E8\u827A\u672F</td><td>\u5F85\u529E\u4E8B\u9879\u5217\u8868\u7F16\u5236<br>\u5F85\u529E\u4E8B\u9879\u5217\u8868\u7684\u7EC6\u5316</td></tr><tr><td>\u6700\u4F73\u7684\u67B6\u6784\u3001\u9700\u6C42\u548C\u8BBE\u8BA1\u5C06\u51FA\u81EA\u4E8E\u81EA\u7EC4\u7EC7\u56E2\u961F</td><td>\u56E2\u961F\u6784\u6210</td></tr><tr><td>\u56E2\u961F\u8981\u5B9A\u671F\u53CD\u7701\u600E\u6837\u505A\u624D\u80FD\u66F4\u6709\u6548\uFF0C\u5E76\u76F8\u5E94\u5730\u8C03\u6574\u56E2\u961F\u7684\u884C\u4E3A</td><td>\u56DE\u987E</td></tr></tbody></table><h2 id="scrum" tabindex="-1"><a class="header-anchor" href="#scrum" aria-hidden="true">#</a> SCRUM</h2><p>Scrum \u662F\u7528\u4E8E\u7BA1\u7406\u4EA7\u54C1\u5F00\u53D1\u7684\u5355\u4E2A\u56E2\u961F\u8FC7\u7A0B\u6846\u67B6\u3002\u8BE5\u6846\u67B6\u5305\u542B Scrum \u89D2\u8272\u3001\u4E8B\u4EF6\u3001\u5DE5\u4EF6\u548C\u89C4\u5219\uFF0C\u91C7\u7528\u8FED\u4EE3\u65B9\u6CD5\u6765\u4EA4\u4ED8\u5DE5\u4F5C\u4EA7\u54C1\u3002Scrum \u662F\u8FD0\u884C\u5728 1 \u4E2A\u6708\u6216\u66F4\u5C11\u65F6\u95F4\u7684\u65F6\u95F4\u76D2\u4E0A\u7684\uFF0C\u5176\u4E2D\u5305\u542B\u6301\u7EED\u65F6\u95F4\u4E00\u81F4\u7684\u591A\u4E2A\u51B2\u523A\uFF0C\u5728\u8FD9\u4E9B\u51B2\u523A\u4E2D\u4F1A\u4EA7\u751F\u6F5C\u5728\u53EF\u53D1\u5E03\u7684\u4EA7\u54C1\u589E\u91CF\u3002</p><p>Scrum \u56E2\u961F\u5305\u542B\u4EA7\u54C1\u8D1F\u8D23\u4EBA\u3001\u5F00\u53D1\u56E2\u961F\u548C Scrum \u4E3B\u7BA1\u3002</p><ul><li>\u4EA7\u54C1\u8D1F\u8D23\u4EBA\u8D1F\u8D23\u5B9E\u73B0\u4EA7\u54C1\u4EF7\u503C\u7684\u6700\u5927\u5316</li><li>\u5F00\u53D1\u56E2\u961F\u662F\u4E00\u4E2A\u8DE8\u804C\u80FD\u81EA\u7EC4\u7EC7\u56E2\u961F\uFF0C\u5176\u5F00\u53D1\u6210\u5458\u62E5\u6709\u6240\u9700\u7684\u4E00\u5207\u8D44\u6E90\uFF0C\u53EF\u5728\u4E0D\u4F9D\u8D56\u56E2\u961F\u5916\u90E8\u5176\u4ED6\u8D44\u6E90\u7684\u60C5\u51B5\u4E0B\u4EA4\u4ED8\u5DE5\u4F5C\u4EA7\u54C1</li><li>Scrum \u4E3B\u7BA1\u8D1F\u8D23\u786E\u4FDD Scrum \u8FC7\u7A0B\u83B7\u5F97\u76F8\u5E94\u652F\u6301\u4E14 Scrum \u56E2\u961F\u9075\u4ECE\u5B9E\u8DF5\u548C\u89C4\u5219\uFF0C\u5E76\u6307\u5BFC\u56E2\u961F\u6D88\u9664\u969C\u788D</li></ul><table><thead><tr><th>\u4E8B\u4EF6</th><th>\u5DE5\u4EF6</th></tr></thead><tbody><tr><td>\u51B2\u523A<br>\u51B2\u523A\u8BA1\u5212<br>\u6BCF\u65E5\u4F8B\u4F1A<br>\u51B2\u523A\u8BC4\u5BA1<br>\u51B2\u523A\u56DE\u987E</td><td>\u4EA7\u54C1\u5F85\u529E\u4E8B\u9879\u5217\u8868<br>\u51B2\u523A\u5F85\u529E\u4E8B\u9879\u5217\u8868<br>\u589E\u91CF</td></tr></tbody></table><h2 id="\u6781\u9650\u7F16\u7A0B" tabindex="-1"><a class="header-anchor" href="#\u6781\u9650\u7F16\u7A0B" aria-hidden="true">#</a> \u6781\u9650\u7F16\u7A0B</h2><p>\u6781\u9650\u7F16\u7A0B\uFF08XP\uFF09\u662F\u4E00\u79CD\u57FA\u4E8E\u9891\u7E41\u4EA4\u4ED8\u5468\u671F\u7684\u8F6F\u4EF6\u5F00\u53D1\u65B9\u6CD5\u3002\u8BE5\u540D\u79F0\u57FA\u4E8E\u8FD9\u6837\u4E00\u4E2A\u7406\u5FF5\uFF1B\u5C06\u7279\u5B9A\u6700\u4F73\u5B9E\u8DF5\u63D0\u70BC\u5230\u6700\u7EAF\u7CB9\u548C\u6700\u7B80\u5355\u7684\u5F62\u5F0F\uFF0C\u7136\u540E\u5728\u6574\u4E2A\u9879\u76EE\u5468\u671F\u5185\u6301\u7EED\u8FD0\u7528\u8BE5\u5B9E\u8DF5\u3002</p><table><thead><tr><th>XP \u5B9E\u8DF5\u9886\u57DF</th><th>\u4E3B\u8981</th><th>\u6B21\u8981</th></tr></thead><tbody><tr><td>\u7EC4\u7EC7</td><td>\u96C6\u4E2D\u529E\u516C<br>\u6574\u4E2A\u56E2\u961F<br>\u4FE1\u606F\u7075\u901A\u7684\u5DE5\u4F5C\u573A\u6240</td><td>\u771F\u5B9E\u5BA2\u6237\u53C2\u4E0E<br>\u56E2\u961F\u8FDE\u7EED\u6027<br>\u53EF\u6301\u7EED\u8282\u594F</td></tr><tr><td>\u6280\u672F</td><td>\u7ED3\u5BF9\u7F16\u7A0B<br>\u6D4B\u8BD5\u4F18\u5148\u7F16\u7A0B<br>\u589E\u91CF\u8BBE\u8BA1</td><td>\u5171\u7528\u4EE3\u7801/\u96C6\u4F53\u6240\u6709\u5236<br>\u4EE3\u7801\u548C\u6D4B\u8BD5\u6587\u6863<br>\u91CD\u6784</td></tr><tr><td>\u89C4\u5212</td><td>\u7528\u6237\u6545\u4E8B<br>\u6BCF\u5468\u5468\u671F<br>\u6BCF\u5B63\u5468\u671F<br>\u65F6\u5DEE</td><td>\u6839\u672C\u539F\u56E0\u5206\u6790<br>\u88C1\u526A\u56E2\u961F<br>\u6309\u4F7F\u7528\u60C5\u51B5\u652F\u4ED8<br>\u534F\u5546\u8303\u56F4\u5408\u540C<br>\u6BCF\u65E5\u7AD9\u4F1A</td></tr><tr><td>\u6574\u5408</td><td>10 \u5206\u949F\u6784\u5EFA<br>\u6301\u7EED\u96C6\u6210<br>\u6D4B\u8BD5\u4F18\u5148</td><td>\u5355\u4EE3\u7801\u5E93<br>\u589E\u91CF\u90E8\u7F72<br>\u6BCF\u65E5\u90E8\u7F72</td></tr></tbody></table><p>\u8BE5\u6F14\u53D8\u662F\u901A\u8FC7\u7B5B\u9009\u6838\u5FC3\u4EF7\u503C\u89C2\uFF08\u6C9F\u901A\u3001\u7B80\u6D01\u3001\u53CD\u9988\u3001\u52C7\u6C14\u3001\u5C0A\u91CD\uFF09\u5E76\u6839\u636E\u4E3B\u8981\u539F\u5219\uFF08\u4EBA\u6027\u5316\u3001\u7ECF\u6D4E\u3001\u4E92\u60E0\u4E92\u5229\u3001\u81EA\u76F8\u4F3C\u3001\u6539\u8FDB\u3001\u591A\u6837\u6027\u3001\u53CD\u601D\u3001\u6D41\u7A0B\u3001\u673A\u4F1A\u3001\u5197\u4F59\u3001\u5931\u8D25\u3001\u8D28\u91CF\u3001\u5FAA\u5E8F\u6E10\u8FDB\u3001\u627F\u62C5\u7684\u8D23\u4EFB\uFF09\u4FE1\u606F\u6765\u8BBE\u8BA1\u548C\u91C7\u7528\u6280\u672F\u7684\u7ED3\u679C\u3002</p><h2 id="\u770B\u677F\u65B9\u6CD5" tabindex="-1"><a class="header-anchor" href="#\u770B\u677F\u65B9\u6CD5" aria-hidden="true">#</a> \u770B\u677F\u65B9\u6CD5</h2><p>\u770B\u677F\u5728\u7CBE\u76CA\u5236\u9020\u4E2D\u662F\u4E00\u79CD\u7528\u4E8E\u89C4\u5212\u5E93\u5B58\u63A7\u5236\u548C\u8865\u7ED9\u7684\u7CFB\u7EDF\u3002\u51C6\u65F6\u5236\u5E93\u5B58\u3002</p><p>\u4EE5\u4E0B\u9700\u8981\u65F6\u770B\u677F\u6700\u4E3A\u9002\u7528</p><ul><li>\u7075\u6D3B\u6027</li><li>\u4E13\u6CE8\u4E8E\u6301\u7EED\u4EA4\u4ED8</li><li>\u63D0\u9AD8\u5DE5\u4F5C\u6548\u7387\u548C\u8D28\u91CF</li><li>\u63D0\u9AD8\u6548\u7387</li><li>\u56E2\u961F\u6210\u5458\u4E13\u6CE8\u529B</li><li>\u5DE5\u4F5C\u8D1F\u8377\u7684\u53EF\u53D8\u6027</li><li>\u51CF\u5C11\u6D6A\u8D39</li></ul><table><thead><tr><th>\u5B9A\u4E49\u539F\u5219</th><th>\u6838\u5FC3\u5C5E\u6027</th></tr></thead><tbody><tr><td>\u4ECE\u5F53\u524D\u72B6\u6001\u5F00\u59CB<br>\u540C\u610F\u91C7\u7528\u589E\u91CF\u6F14\u53D8\u6027\u53D8\u66F4<br>\u5C0A\u91CD\u5F53\u524D\u8FC7\u7A0B\u3001\u89D2\u8272\u3001\u804C\u8D23\u548C\u5934\u8854<br>\u9F13\u52B1\u6240\u6709\u5C42\u7EA7\u9886\u5BFC\u884C\u4E3A</td><td>\u5DE5\u4F5C\u6D41\u53EF\u89C6\u5316<br>\u9650\u5236\u5728\u5236\u54C1<br>\u7BA1\u7406\u6D41\u7A0B<br>\u660E\u786E\u8FC7\u7A0B\u653F\u7B56<br>\u5B9E\u65BD\u53CD\u9988\u5FAA\u73AF<br>\u63D0\u9AD8\u534F\u4F5C\u6027</td></tr></tbody></table><p>\u5728\u770B\u677F\u65B9\u6CD5\u4E2D\uFF0C\u5B8C\u6210\u5DE5\u4F5C\u6BD4\u5F00\u59CB\u65B0\u5DE5\u4F5C\u66F4\u4E3A\u91CD\u8981\uFF0C\u4ECE\u672A\u5B8C\u6210\u7684\u5DE5\u4F5C\u4E2D\u65E0\u6CD5\u83B7\u5F97\u4EFB\u4F55\u4EF7\u503C\u3002</p><h2 id="\u6C34\u6676\u65B9\u6CD5" tabindex="-1"><a class="header-anchor" href="#\u6C34\u6676\u65B9\u6CD5" aria-hidden="true">#</a> \u6C34\u6676\u65B9\u6CD5</h2><table><thead><tr><th>\u6838\u5FC3\u4EF7\u503C\u89C2</th><th>\u5E38\u89C1\u5C5E\u6027</th></tr></thead><tbody><tr><td>\u4EBA\u5458<br>\u4EA4\u4E92<br>\u793E\u533A<br>\u6280\u80FD<br>\u4EBA\u624D<br>\u6C9F\u901A</td><td>\u9891\u7E41\u4EA4\u4ED8<br>\u53CD\u601D\u5F0F\u6539\u8FDB<br>\u5BC6\u5207\u6216\u6E17\u900F\u578B\u6C9F\u901A<br>\u4E2A\u4EBA\u5B89\u5168<br>\u4E13\u6CE8<br>\u5BB9\u6613\u63A5\u89E6\u4E13\u5BB6\u7528\u6237<br>\u5177\u6709\u81EA\u52A8\u5316\u6D4B\u8BD5\u3001\u914D\u7F6E\u7BA1\u7406\u548C\u9891\u7E41\u6574\u5408\u7684\u6280\u672F\u73AF\u5883</td></tr></tbody></table><h2 id="scrumban" tabindex="-1"><a class="header-anchor" href="#scrumban" aria-hidden="true">#</a> SCRUMBAN</h2><p>\u56E2\u961F\u5C06 Scrum \u4F5C\u4E3A\u6846\u67B6\uFF0C\u800C\u5C06\u770B\u677F\u4F5C\u4E3A\u8FC7\u7A0B\u6539\u8FDB\u65B9\u6CD5\u3002</p><p>\u5DE5\u4F5C\u88AB\u5206\u89E3\u5230\u8BB8\u591A\u5C0F\u7684\u201C\u51B2\u523A\u201D\uFF0C\u5E76\u5229\u7528\u770B\u677F\u9762\u677F\u6765\u53EF\u89C6\u5316\u548C\u76D1\u7763\u5DE5\u4F5C\u3002</p><h2 id="\u529F\u80FD\u9A71\u52A8\u5F00\u53D1-fdd" tabindex="-1"><a class="header-anchor" href="#\u529F\u80FD\u9A71\u52A8\u5F00\u53D1-fdd" aria-hidden="true">#</a> \u529F\u80FD\u9A71\u52A8\u5F00\u53D1\uFF08FDD\uFF09</h2><p>\u76EE\u7684\u662F\u6EE1\u8DB3\u5927\u578B\u8F6F\u4EF6\u5F00\u53D1\u9879\u76EE\u7684\u7279\u5B9A\u9700\u6C42\u3002\u5C0F\u578B\u5546\u4E1A\u4EF7\u503C\u529F\u80FD\u91CD\u89C6\u80FD\u529B\u3002</p><p>\u516D\u4E2A\u4E3B\u8981\u89D2\u8272\uFF0C\u6BCF\u4E2A\u4EBA\u53EF\u4EE5\u62C5\u4EFB\u4EE5\u4E0B\u4E00\u4E2A\u6216\u591A\u4E2A\u89D2\u8272\uFF1A</p><ul><li>\u9879\u76EE\u7ECF\u7406</li><li>\u9996\u5E2D\u67B6\u6784\u5E08</li><li>\u5F00\u53D1\u7ECF\u7406</li><li>\u9996\u5E2D\u7F16\u7A0B\u4EBA\u5458</li><li>\u7C7B\u8D1F\u8D23\u4EBA</li><li>\u9886\u57DF\u4E13\u5BB6</li></ul><p>\u4E94\u4E2A\u8FC7\u7A0B\u6216\u6D3B\u52A8\uFF0C\u4EE5\u8FED\u4EE3\u65B9\u5F0F\u6267\u884C\uFF1A</p><ul><li>\u5F00\u53D1\u6574\u4E2A\u6A21\u578B</li><li>\u6784\u5EFA\u529F\u80FD\u5217\u8868</li><li>\u4F9D\u636E\u529F\u80FD\u89C4\u5212</li><li>\u4F9D\u636E\u529F\u80FD\u8BBE\u8BA1</li><li>\u4F9D\u636E\u529F\u80FD\u6784\u5EFA</li></ul><p>\u6838\u5FC3\u8F6F\u4EF6\u5DE5\u7A0B\u6700\u4F73\u5B9E\u8DF5\u63D0\u4F9B\u652F\u6301\uFF1A</p><ul><li>\u9886\u57DF\u5BF9\u8C61\u5EFA\u6A21</li><li>\u4F9D\u636E\u529F\u80FD\u5F00\u53D1</li><li>\u4E2A\u4F53\u4EE3\u7801\u6240\u6709\u5236</li><li>\u529F\u80FD\u56E2\u961F</li><li>\u68C0\u67E5</li><li>\u914D\u7F6E\u7BA1\u7406</li><li>\u5B9A\u671F\u6784\u5EFA</li><li>\u8FDB\u5EA6\u548C\u7ED3\u679C\u53EF\u89C6\u5316</li></ul><h2 id="\u52A8\u6001\u7CFB\u7EDF\u5F00\u53D1\u65B9\u6CD5-dsdm" tabindex="-1"><a class="header-anchor" href="#\u52A8\u6001\u7CFB\u7EDF\u5F00\u53D1\u65B9\u6CD5-dsdm" aria-hidden="true">#</a> \u52A8\u6001\u7CFB\u7EDF\u5F00\u53D1\u65B9\u6CD5\uFF08DSDM\uFF09</h2><p>\u8BE5\u6846\u67B6\u5F00\u53D1\u4E3A\u884C\u4E1A\u9886\u5BFC\u8005\u4E4B\u95F4\u7684\u975E\u5546\u4E1A\u6027\u534F\u4F5C\u65B9\u5F0F\u3002</p><p>DSDM \u56E0\u5F3A\u8C03\u5236\u7EA6\u56E0\u7D20\u9A71\u52A8\u4EA4\u4ED8\u800C\u8457\u79F0\u3002\u8BE5\u6846\u67B6\u4ECE\u4E00\u5F00\u59CB\u4FBF\u53EF\u8BBE\u7F6E\u6210\u672C\u3001\u8D28\u91CF\u548C\u5B9E\u8DF5\uFF0C\u7136\u540E\u5229\u7528\u6B63\u5F0F\u7684\u8303\u56F4\u4F18\u5148\u7EA7\u6765\u6EE1\u8DB3\u8FD9\u4E9B\u5236\u7EA6\u56E0\u7D20\u7684\u8981\u6C42\u3002</p><p>\u516B\u4E2A\u539F\u5219\u6765\u6307\u5BFC DSDM \u6846\u67B6\u7684\u4F7F\u7528\uFF1A</p><ul><li>\u4E13\u6CE8\u4E8E\u4E1A\u52A1\u9700\u6C42</li><li>\u51C6\u65F6\u4EA4\u4ED8</li><li>\u534F\u4F5C</li><li>\u5728\u8D28\u91CF\u4E0A\u6C38\u4E0D\u59A5\u534F</li><li>\u5728\u575A\u5B9E\u7684\u57FA\u7840\u4E0A\u8FDB\u884C\u589E\u91CF\u5F0F\u6784\u5EFA</li><li>\u8FED\u4EE3\u5F00\u53D1</li><li>\u4FDD\u6301\u6301\u7EED\u548C\u660E\u6670\u7684\u6C9F\u901A</li><li>\u6F14\u793A\u63A7\u5236\uFF08\u4F7F\u7528\u9002\u5F53\u7684\u6280\u672F\uFF09</li></ul><h2 id="\u654F\u6377\u7EDF\u4E00\u8FC7\u7A0B-agileup" tabindex="-1"><a class="header-anchor" href="#\u654F\u6377\u7EDF\u4E00\u8FC7\u7A0B-agileup" aria-hidden="true">#</a> \u654F\u6377\u7EDF\u4E00\u8FC7\u7A0B\uFF08AgileUP\uFF09</h2><p>\u4E3B\u8981\u5143\u7D20</p><table><thead><tr><th>\u53D1\u5E03\u4E2D\u7684\u56E0\u7D20</th><th>\u6307\u5BFC\u56E0\u7D20\u7684\u539F\u5219</th></tr></thead><tbody><tr><td>\u6A21\u578B<br>\u5B9E\u65BD<br>\u6D4B\u8BD5<br>\u90E8\u7F72<br>\u914D\u7F6E\u7BA1\u7406<br>\u9879\u76EE\u7BA1\u7406<br>\u73AF\u5883</td><td>\u56E2\u961F\u4E86\u89E3\u5F53\u524D\u5DE5\u4F5C<br>\u7B80\u6D01\u6027<br>\u654F\u6377\u6027<br>\u4E13\u6CE8\u4E8E\u9AD8\u4EF7\u503C\u6D3B\u52A8<br>\u5DE5\u5177\u4F9D\u8D56\u6027<br>\u91CF\u8EAB\u5B9A\u5236<br>\u7279\u5B9A\u60C5\u5883</td></tr></tbody></table><h2 id="scrum-of-scrums" tabindex="-1"><a class="header-anchor" href="#scrum-of-scrums" aria-hidden="true">#</a> SCRUM OF SCRUMS</h2><h2 id="\u5927\u89C4\u6A21\u654F\u6377\u6846\u67B6-safe" tabindex="-1"><a class="header-anchor" href="#\u5927\u89C4\u6A21\u654F\u6377\u6846\u67B6-safe" aria-hidden="true">#</a> \u5927\u89C4\u6A21\u654F\u6377\u6846\u67B6\uFF08SAFe\uFF09</h2><p>SAFe \u4E13\u6CE8\u4E8E\u5728\u9879\u76EE\u7EC4\u5408\u3001\u9879\u76EE\u96C6\u548C\u56E2\u961F\u5C42\u8BE6\u7EC6\u8BBE\u5B9A\u5B9E\u8DF5\u3001\u89D2\u8272\u548C\u6D3B\u52A8\uFF0C\u5F3A\u8C03\u56F4\u7ED5\u4E13\u6CE8\u4E8E\u5411\u5BA2\u6237\u63D0\u4F9B\u6301\u7EED\u4EF7\u503C\u7684\u4EF7\u503C\u6D41\u6765\u7EC4\u7EC7\u4F01\u4E1A\u3002</p><ul><li>\u91C7\u7528\u7ECF\u6D4E\u89C6\u89D2</li><li>\u5E94\u7528\u7CFB\u7EDF\u601D\u7EF4</li><li>\u5047\u8BBE\u53EF\u53D8\u6027\uFF1B\u9884\u7559\u65B9\u6848</li><li>\u4EE5\u5FEB\u901F\u6574\u5408\u7684\u5B66\u4E60\u5468\u671F\u8FDB\u884C\u589E\u91CF\u5F0F\u6784\u5EFA</li><li>\u6839\u636E\u5BF9\u5DE5\u4F5C\u7CFB\u7EDF\u7684\u5BA2\u89C2\u8BC4\u4F30\u8BBE\u5B9A\u91CC\u7A0B\u7891</li><li>\u76F4\u89C2\u663E\u793A\u5E76\u9650\u5236\u5728\u5236\u54C1\uFF0C\u51CF\u5C0F\u6279\u6B21\u89C4\u6A21\u5E76\u7BA1\u7406\u961F\u5217\u957F\u5EA6</li><li>\u5E94\u7528\u8282\u594F\uFF1B\u4E0E\u8DE8\u57DF\u89C4\u5212\u540C\u6B65</li><li>\u89E3\u9501\u77E5\u8BC6\u5458\u5DE5\u7684\u5185\u5728\u52A8\u529B</li><li>\u51B3\u7B56\u5206\u6563\u5316</li></ul><h2 id="\u5927\u89C4\u6A21\u654F\u6377\u5F00\u53D1-less" tabindex="-1"><a class="header-anchor" href="#\u5927\u89C4\u6A21\u654F\u6377\u5F00\u53D1-less" aria-hidden="true">#</a> \u5927\u89C4\u6A21\u654F\u6377\u5F00\u53D1\uFF08LeSS\uFF09</h2><p>\u4EE5\u6269\u5C55 Scrum \u65B9\u6CD5\u4E3A\u5171\u540C\u76EE\u6807\u6765\u7EC4\u7EC7\u591A\u4E2A\u5F00\u53D1\u56E2\u961F\u7684\u6846\u67B6\uFF0C\u5176\u6838\u5FC3\u539F\u5219\u662F\u5C3D\u53EF\u80FD\u535A\u963F\u7559\u4F20\u7EDF\u5355\u4E2A\u56E2\u961F Scrum \u6A21\u578B\u7684\u5143\u7D20\u3002</p><table><thead><tr><th>LeSS \u4E0E Scrum \u7684\u76F8\u4F3C\u6027</th><th>\u5728 Scrum \u4E2D\u6DFB\u52A0 LeSS \u6280\u672F</th></tr></thead><tbody><tr><td>\u4E00\u4E2A\u4EA7\u54C1\u5F85\u529E\u4E8B\u9879\u5217\u8868<br>\u4E00\u4E2A\u6240\u6709\u9879\u76EE\u5B8C\u6210\u7684\u5B9A\u4E49<br>\u4E00\u4E2A\u53EF\u5728\u6BCF\u4E2A\u51B2\u523A\u7ED3\u675F\u65F6\u6F5C\u5728\u53EF\u4EA4\u4ED8\u7684\u4EA7\u54C1\u589E\u91CF<br>\u4E00\u540D\u4EA7\u54C1\u8D1F\u8D23\u4EBA<br>\u5168\u9762\u7684\u8DE8\u804C\u80FD\u56E2\u961F<br>\u4E00\u4E2A\u51B2\u523A</td><td>\u51B2\u523A\u8BA1\u5212\u5206\u4E3A\u4E24\u4E2A\u6B63\u5F0F\u90E8\u5206\uFF1A\u51B2\u523A\u5185\u5BB9\u548C\u65B9\u5F0F<br>\u6709\u673A\u8DE8\u56E2\u961F\u5408\u4F5C<br>\u6574\u4F53\u8DE8\u56E2\u961F\u4F18\u5316<br>\u4E13\u6CE8\u4E8E\u8DE8\u56E2\u961F\u6539\u8FDB\u7684\u6574\u4F53\u56DE\u987E</td></tr></tbody></table><h2 id="\u4F01\u4E1A-scrum" tabindex="-1"><a class="header-anchor" href="#\u4F01\u4E1A-scrum" aria-hidden="true">#</a> \u4F01\u4E1A SCRUM</h2><p>\u65E8\u5728\u901A\u8FC7\u66F4\u6574\u4F53\u6027\u7EC4\u7EC7\u5C42\u800C\u4E0D\u662F\u5355\u4E2A\u4EA7\u54C1\u5F00\u53D1\u5C42\u6765\u5E94\u7528 Scrum \u65B9\u6CD5\u7684\u6846\u67B6\u3002\u8BE5\u6846\u67B6\u5C24\u5176\u5EFA\u8BAE\u7EC4\u7EC7\u9886\u5BFC\uFF1A</p><ul><li>\u5C06\u6240\u6709 Scrum \u5E94\u7528\u6269\u5C55\u5230\u6240\u6709\u7EC4\u7EC7\u65B9\u9762</li><li>\u666E\u53CA Scrum \u6280\u672F\u4EE5\u4FBF\u5728\u8FD9\u4E9B\u4E0D\u540C\u7684\u65B9\u9762\u8F7B\u677E\u5E94\u7528</li><li>\u6839\u636E\u9700\u8981\u4F7F\u7528\u8865\u5145\u6280\u672F\u6269\u5C55 Scrum \u65B9\u6CD5</li></ul><p>\u5176\u76EE\u7684\u5728\u4E8E\u901A\u8FC7\u5B9E\u73B0\u98A0\u8986\u6027\u521B\u65B0\u5C06\u654F\u6377\u65B9\u6CD5\u6269\u5C55\u5230\u9879\u76EE\u6267\u884C\u8303\u56F4\u4EE5\u5916\u3002</p><h2 id="\u89C4\u8303\u654F\u6377-da" tabindex="-1"><a class="header-anchor" href="#\u89C4\u8303\u654F\u6377-da" aria-hidden="true">#</a> \u89C4\u8303\u654F\u6377\uFF08DA\uFF09</h2><p>\u5728\u7EFC\u5408\u6A21\u578B\u4E2D\u6574\u5408\u591A\u79CD\u654F\u6377\u6700\u4F73\u5B9E\u8DF5\u7684\u8FC7\u7A0B\u51B3\u7B56\u6846\u67B6\u3002DA \u65E8\u5728\u5E73\u8861\u4E13\u6CE8\u8303\u56F4\u8FC7\u4E8E\u72ED\u7A84\uFF08\u5982 Scrum\uFF09\u6216\u7EC6\u8282\u8FC7\u4E8E\u89C4\u8303\uFF08\u5982 AgileUP\uFF09\u7684\u6D41\u884C\u65B9\u6CD5\u3002\u4E3A\u5B9E\u73B0\u8FD9\u79CD\u5E73\u8861\uFF0C\u8BE5\u65B9\u6CD5\u6839\u636E\u4EE5\u4E0B\u539F\u5219\u6DF7\u5408\u4E86\u591A\u79CD\u654F\u6377\u6280\u672F\uFF1A</p><ul><li>\u4EE5\u4EBA\u4E3A\u5148\uFF1A\u679A\u4E3E\u4E0D\u540C\u5C42\u7EA7\u7684\u89D2\u8272\u548C\u7EC4\u7EC7\u5143\u7D20</li><li>\u9762\u5411\u5B66\u4E60\uFF1A\u9F13\u52B1\u534F\u4F5C\u6539\u8FDB</li><li>\u5B8C\u5168\u4EA4\u4ED8\u751F\u547D\u5468\u671F\uFF1A\u63D0\u5021\u591A\u4E2A\u7B26\u5408\u76EE\u7684\u7684\u751F\u547D\u5468\u671F</li><li>\u76EE\u6807\u9A71\u52A8\uFF1A\u5B9A\u5236\u8FC7\u7A0B\u4EE5\u5B9E\u73B0\u7279\u5B9A\u7ED3\u679C</li><li>\u4F01\u4E1A\u610F\u8BC6\uFF1A\u63D0\u4F9B\u8DE8\u90E8\u95E8\u6CBB\u7406\u65B9\u9762\u7684\u6307\u5BFC</li><li>\u53EF\u6269\u5C55\uFF1A\u6DB5\u76D6\u591A\u79CD\u9879\u76EE\u590D\u6742\u6027\u7EF4\u5EA6</li></ul>',54);function a(l,e){return i}var b=t(d,[["render",a],["__file","appendix1.html.vue"]]);export{b as default};
